  // ── AI assistant ───────────────────────────────────────────────────
  "Bonjour 👋 Je suis **Orbit IA**. Pose-moi une question, demande-moi de **piloter l'app** (« va dans l'interpolateur IA », « coupe le proxy », « masque tous les onglets »…), ou glisse-dépose un fichier.": { en: "Hi 👋 I'm **Orbit AI**. Ask me a question, tell me to **drive the app** (\"go to the AI interpolator\", \"turn off the proxy\", \"hide all tabs\"…), or drag and drop a file.", es: "Hola 👋 Soy **Orbit IA**. Hazme una pregunta, pídeme que **controle la app** (\"ve al interpolador IA\", \"desactiva el proxy\", \"oculta todas las pestañas\"…), o arrastra un archivo.", de: "Hallo 👋 Ich bin **Orbit KI**. Stell mir eine Frage, lass mich **die App steuern** (\"geh zum KI-Interpolator\", \"Proxy aus\", \"alle Tabs ausblenden\"…) oder zieh eine Datei hierher.", it: "Ciao 👋 Sono **Orbit IA**. Fammi una domanda, chiedimi di **pilotare l'app** (\"vai all'interpolatore IA\", \"disattiva il proxy\", \"nascondi tutte le schede\"…) o trascina un file.", pt: "Olá 👋 Sou a **Orbit IA**. Faça uma pergunta, peça para eu **controlar o app** (\"vá para o interpolador IA\", \"desligue o proxy\", \"oculte todas as abas\"…) ou arraste um arquivo." },
  "✅ Je récupère l'audio de ce lien — direction Téléchargements.": { en: "✅ Grabbing the audio from this link — heading to Downloads.", es: "✅ Obtengo el audio de este enlace — voy a Descargas.", de: "✅ Ich hole das Audio dieses Links — auf zu Downloads.", it: "✅ Recupero l'audio di questo link — vado in Download.", pt: "✅ Pegando o áudio deste link — indo para Downloads." },
  "✅ Je télécharge cette vidéo pour toi — direction Téléchargements.": { en: "✅ Downloading this video for you — heading to Downloads.", es: "✅ Descargo este vídeo por ti — voy a Descargas.", de: "✅ Ich lade dieses Video für dich herunter — auf zu Downloads.", it: "✅ Scarico questo video per te — vado in Download.", pt: "✅ Baixando este vídeo para você — indo para Downloads." },
  "✅ Direction Téléchargements ! Colle le lien de la vidéo ici ou dans la barre, et je m'en occupe automatiquement.": { en: "✅ Off to Downloads! Paste the video link here or in the bar and I'll handle it automatically.", es: "✅ ¡A Descargas! Pega el enlace del vídeo aquí o en la barra y me ocupo automáticamente.", de: "✅ Auf zu Downloads! Füge den Videolink hier oder in der Leiste ein, ich kümmere mich automatisch darum.", it: "✅ Direzione Download! Incolla il link del video qui o nella barra e me ne occupo automaticamente.", pt: "✅ Rumo a Downloads! Cole o link do vídeo aqui ou na barra e eu cuido automaticamente." },
  "✅ J'ai masqué tous les onglets (Téléchargements reste actif pour garder l'app utilisable).": { en: "✅ I hid all tabs (Downloads stays active to keep the app usable).", es: "✅ Oculté todas las pestañas (Descargas sigue activa para que la app sea usable).", de: "✅ Ich habe alle Tabs ausgeblendet (Downloads bleibt aktiv, damit die App nutzbar bleibt).", it: "✅ Ho nascosto tutte le schede (Download resta attivo per mantenere l'app usabile).", pt: "✅ Ocultei todas as abas (Downloads permanece ativo para manter o app utilizável)." },
  "✅ J'ai réaffiché tous les onglets.": { en: "✅ I brought back all tabs.", es: "✅ Volví a mostrar todas las pestañas.", de: "✅ Ich habe alle Tabs wieder eingeblendet.", it: "✅ Ho rimostrato tutte le schede.", pt: "✅ Reexibi todas as abas." },
  "✅ Proxy désactivé.": { en: "✅ Proxy disabled.", es: "✅ Proxy desactivado.", de: "✅ Proxy deaktiviert.", it: "✅ Proxy disattivato.", pt: "✅ Proxy desativado." },
  "✅ Thème sombre activé.": { en: "✅ Dark theme enabled.", es: "✅ Tema oscuro activado.", de: "✅ Dunkles Design aktiviert.", it: "✅ Tema scuro attivato.", pt: "✅ Tema escuro ativado." },
  "✅ Thème clair activé.": { en: "✅ Light theme enabled.", es: "✅ Tema claro activado.", de: "✅ Helles Design aktiviert.", it: "✅ Tema chiaro attivato.", pt: "✅ Tema claro ativado." },
  "✅ Notifications désactivées.": { en: "✅ Notifications disabled.", es: "✅ Notificaciones desactivadas.", de: "✅ Benachrichtigungen deaktiviert.", it: "✅ Notifiche disattivate.", pt: "✅ Notificações desativadas." },
  "✅ Notifications activées.": { en: "✅ Notifications enabled.", es: "✅ Notificaciones activadas.", de: "✅ Benachrichtigungen aktiviert.", it: "✅ Notifiche attivate.", pt: "✅ Notificações ativadas." },
  "✅ J'ai ouvert les paramètres.": { en: "✅ I opened the settings.", es: "✅ Abrí los ajustes.", de: "✅ Ich habe die Einstellungen geöffnet.", it: "✅ Ho aperto le impostazioni.", pt: "✅ Abri as configurações." },
  "✅ J'ai ouvert l'outil d'import.": { en: "✅ I opened the import tool.", es: "✅ Abrí la herramienta de importación.", de: "✅ Ich habe das Import-Werkzeug geöffnet.", it: "✅ Ho aperto lo strumento di importazione.", pt: "✅ Abri a ferramenta de importação." },
  "✅ J'ai masqué l'onglet « {tab} ».": { en: "✅ I hid the \"{tab}\" tab.", es: "✅ Oculté la pestaña «{tab}».", de: "✅ Ich habe den Tab „{tab}\" ausgeblendet.", it: "✅ Ho nascosto la scheda «{tab}».", pt: "✅ Ocultei a aba «{tab}»." },
  "✅ J'ai affiché l'onglet « {tab} ».": { en: "✅ I showed the \"{tab}\" tab.", es: "✅ Mostré la pestaña «{tab}».", de: "✅ Ich habe den Tab „{tab}\" eingeblendet.", it: "✅ Ho mostrato la scheda «{tab}».", pt: "✅ Exibi a aba «{tab}»." },
  "✅ Direction l'onglet « {tab} » !": { en: "✅ Off to the \"{tab}\" tab!", es: "✅ ¡A la pestaña «{tab}»!", de: "✅ Auf zum Tab „{tab}\"!", it: "✅ Direzione scheda «{tab}»!", pt: "✅ Rumo à aba «{tab}»!" },
  "Un fichier vient d'être déposé : \"{file}\". L'onglet actif est \"{tab}\". Propose-moi ce que je peux faire avec ce fichier.": { en: "A file was just dropped: \"{file}\". The active tab is \"{tab}\". Suggest what I can do with this file.", es: "Se acaba de soltar un archivo: \"{file}\". La pestaña activa es \"{tab}\". Sugiéreme qué puedo hacer con este archivo.", de: "Eine Datei wurde abgelegt: \"{file}\". Der aktive Tab ist \"{tab}\". Schlag vor, was ich mit dieser Datei machen kann.", it: "È stato appena rilasciato un file: \"{file}\". La scheda attiva è \"{tab}\". Suggeriscimi cosa posso fare con questo file.", pt: "Um arquivo acabou de ser solto: \"{file}\". A aba ativa é \"{tab}\". Sugira o que posso fazer com este arquivo." },
